"""
mkt-original | zechariah | ch14 | 21 verses
run: python3 scripts/zc-original-zechariah-14-14.py

Key interpretation decisions:
- v4: har ha-zeitim (Mount of Olives) splits east-west; Acts 1:11 ascension/return connection
- v5: qedoshim (holy ones) = angels/saints in eschatological retinue; 1 Thess 3:13; Matt 25:31
- v7: yom echad (one unique day) = eschatological time outside normal cycle; Rev 21:25; 22:5
- v8: mayim chayyim (living waters) from Jerusalem = Ezek 47; John 7:38; Rev 22:1-2
- v9: YHWH echad ushmo echad = Shema applied to eschatological resolution; 1 Cor 15:28; Rev 11:15
- v16: chag ha-sukkot (Feast of Tabernacles) = universal eschatological harvest feast
- v20: qodesh l-YHWH on horse bells = High Priest's headband inscription universalized (Exod 28:36-37)
- v21: kena'ani = both 'Canaanite' and 'merchant/trader'; no commerce in the eschatological temple;
       Jesus's temple cleansing (John 2:16) enacts this eschatological purification in advance
"""

import json, pathlib

ROOT = pathlib.Path(__file__).resolve().parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        existing.setdefault(ch, {})
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ZECHARIAH = {
  "14": {
    "1": "<p><span class='term'>A day is coming for the LORD</span> — <em>hineh yom ba l-YHWH</em>: the absolute <em>yom YHWH</em> (Day of the LORD) formula; the chapter is Zechariah's fullest treatment of the eschatological Day. <em>Vechalaq shelalekh beqirbekha</em> (the plunder taken from you will be divided in your midst) — the shocking opening: Jerusalem's own spoil is distributed by the invaders within the city; the covenant-curse of Lev 26:32-33 (I will scatter you among the nations) has reached its ultimate expression. The eschatological Day begins not with immediate triumph but with Jerusalem's most extreme humiliation.</p>",
    "2": "<p><span class='term'>I will gather all the nations against Jerusalem to fight</span> — <em>ve'asafti et-kol-ha-goyim el-Yerushalaim la-milchamah</em>: YHWH himself gathers the nations against his own city — the divine paradox that sustains the entire chapter. <em>Venilkedah ha-ir</em> (the city will be taken) — the Babylonian-pattern defeat described with the same vocabulary as 586 BCE; but this is the eschatological repetition. <em>Ve'yatza chitzi ha-ir ba-golah</em> (half the city will go into exile) — the partial rather than total deportation signals that the judgment is restrained, not final; it is followed immediately by the divine reversal in v3.</p>",
    "3": "<p><span class='term'>Then the LORD will march out and fight those nations, as he fights in the day of battle</span> — <em>veyatza YHWH venilcham ba-goyim ha-hem</em>: the Divine Warrior motif in its purest form. <em>Ke-yom hilachamo beyom qerav</em> (as he fights in a day of battle) — the comparison is to all the great warrior-interventions in Israel's history: the Reed Sea (Exod 14:14), the Gibeon battle (Josh 10:14), Deborah's campaign (Judg 5:4-5). The eschatological war recapitulates every prior instance of divine combat in Israel's history, transcending them all.</p>",
    "4": "<p><span class='term'>On that day his feet will stand on the Mount of Olives</span> — <em>veamdu raglaw bayom hahu al-har ha-zeitim</em>: the literal standing of YHWH's feet on the Mount of Olives is the most direct theophany-language in Zechariah. <em>Har ha-zeitim</em> (Mount of Olives) faces Jerusalem to the east — the direction from which YHWH's glory departed (Ezek 11:23: 'the glory of the LORD stopped above the mountain east of Jerusalem') and to which it returns (Ezek 43:2). The mountain's splitting (<em>nivqa har ha-zeitim mechetzyo</em>, split from the middle) echoes the Reed Sea splitting and creates the escape route of v5. Acts 1:11 ('this Jesus... will come in the same way as you saw him go into heaven') implicitly connects the ascension site with the return site.</p>",
    "5": "<p><span class='term'>Then the LORD my God will come, and all the holy ones with him</span> — <em>uba YHWH elohai kol-qedoshim immakh</em>: the parousia formula in its OT form. <em>Qedoshim</em> (holy ones) = the angelic-divine retinue (Deut 33:2: 'the LORD came from Sinai... with ten thousand holy ones'); the same assembly Paul references in 1 Thess 3:13 ('at the coming of our Lord Jesus with all his holy ones') and in 2 Thess 1:7 ('the Lord Jesus is revealed from heaven with his mighty angels'). The earthquake simile references the historical Uzziah earthquake (Amos 1:1), which had become proverbial for an overwhelming seismic event.</p>",
    "6": "<p><span class='term'>On that day there will be neither bright light nor heavy darkness</span> — <em>vehayah bayom hahu lo yihyeh or yeqarot veqippa'on</em>: the eschatological alteration of the light-dark cycle is one of the most distinctive features of Zech 14's cosmology. The precise meaning of <em>yeqarot</em> and <em>qippa'on</em> is debated — probably 'brilliant lights' and 'thickening/clouding' — but the net effect is the suspension of the normal day-night binary. The same eschatological light-abnormality appears in Isa 60:19-20 ('your sun will never set again; your moon will not withdraw') and in Rev 21:23 ('the city does not need sun or moon').</p>",
    "7": "<p><span class='term'>It will be one unique day — known only to the LORD — with no distinction between day and night. But at evening time there will be light</span> — <em>vehayah yom echad hu' yivvada' l-YHWH lo yom velo lailah</em>: <em>yom echad</em> (one unique day) — the singular eschatological day that transcends the seven-day creation cycle; 'known only to YHWH' implies that the time of this day belongs entirely to divine knowledge (cf. Matt 24:36: 'no one knows the day or the hour, not even the angels, but only the Father'). <em>Ve-hayah le-et erev yihyeh or</em> (at evening time there will be light) — the paradox of light coming at evening inverts the creation pattern (Gen 1:5: 'there was evening and there was morning') and anticipates Rev 22:5 ('there will be no more night').</p>",
    "8": "<p><span class='term'>On that day, living waters will flow out from Jerusalem</span> — <em>vehayah bayom hahu yetz'u mayim chayyim miYerushalaim</em>: <em>mayim chayyim</em> (living/flowing waters) = fresh, perennial, life-giving waters — the technical term distinguishing spring water from cistern water (Lev 14:5-6; Jer 2:13: 'my people have forsaken me, the spring of living water'). The bifurcation — <em>chatso el-ha-yam ha-qadmoni vechatso el-ha-yam ha-acharon</em> (half toward the eastern sea and half toward the western sea) — covers the entire land. The direct intertextual parallels: Ezek 47:1-12 (water flowing from the temple threshold), Joel 3:18 (a spring will flow from the LORD's house), and John 7:38 (Jesus: 'from within him will flow rivers of living water') and Rev 22:1-2 (the river of life from the throne of God and the Lamb).</p>",
    "9": "<p><span class='term'>The LORD will be king over all the earth. On that day the LORD will be one and his name one</span> — <em>vehayah YHWH lemelekh al kol ha-aretz bayom hahu yihyeh YHWH echad ushmo echad</em>: the Shema of Deut 6:4 (<em>YHWH eloheinu YHWH echad</em>) applied eschatologically. In the present age the <em>echad</em> is confessed but not universally acknowledged; in the Day of YHWH it becomes the actual condition of all reality. The NT applies the eschatological <em>echad</em> formula at two points: 1 Cor 15:28 ('God will be all in all') and Rev 11:15 ('the kingdom of the world has become the kingdom of our Lord and of his Christ, and he shall reign forever and ever'). The Shema that Israel confesses daily in the present age becomes the cosmological fact of the new creation.</p>",
    "10": "<p><span class='term'>The whole land will be changed into a plain from Geba to Rimmon south of Jerusalem, but Jerusalem will be elevated</span> — <em>yissov kol ha-aretz ka'aravah</em> (the whole land will become like the Arabah/plain): a geographic flattening so that Jerusalem's elevation becomes supremely visible. The leveling of the surrounding topography while Jerusalem is raised recalls Isa 2:2 ('the mountain of the house of the LORD shall be established as the highest of the mountains, and shall be lifted up above the hills; and all the nations shall flow to it'). <em>Misha'ar Binyamin</em> to the <em>Makom ha-Rishon</em> (the Old Gate) to the Corner Gate to the Tower of Hananel to the King's winepresses — the specific boundaries delineate the eschatological Jerusalem as a concrete place, not merely a symbol.</p>",
    "11": "<p><span class='term'>Jerusalem will be inhabited; there will be no more ban of destruction, and Jerusalem will live in security</span> — <em>veyashvah vah ve-cherem lo yihyeh od</em>: <em>cherem</em> (ban of destruction, total devotion/dedication to destruction) was the covenant-war term for the irrevocable destruction of captured peoples and cities (Josh 6:17 — Jericho; 1 Sam 15:3 — Amalek). The promise that Jerusalem will no longer be <em>cherem</em> reverses both Jeremiah's curses (Jer 25:9) and the Babylonian destruction. <em>Lavvetach</em> (in security) — the covenantal <em>betach</em> (security, unafraid) that was the promised condition of the covenant land (Lev 26:5; Deut 12:10).</p>",
    "12": "<p><span class='term'>Their flesh will rot while they are still standing, their eyes will rot in their sockets, their tongues will rot in their mouths</span> — <em>veze tihyeh ha-maggefah asher yiggof YHWH et-kol-ha'ammim</em>: the plague of physical decay while still living (<em>beamdam al ragleihem</em>) is a reverse of the normal death-sequence: the body dissolves before death rather than after. The three-part specification — flesh, eyes, tongue — is the same sequence as Ps 73:7 and Isa 59:9-10 for spiritual blindness and dumbness; here literalized as the eschatological judgment that finally expresses in the body what has long been true spiritually. The NT's 'fire that never goes out' and 'worm that never dies' (Mark 9:43-48, citing Isa 66:24) carry the same non-ordinary decay imagery.</p>",
    "13": "<p><span class='term'>On that day a great panic from the LORD will come upon them: each man will seize the hand of his neighbor, and one will turn against the other</span> — <em>umehuma-gedolah YHWH bam</em>: the <em>mehumah</em> (panic, confusion, consternation) is a formal covenant-curse term (Deut 28:20: 'the LORD will send on you cursing, confusion, and frustration in all that you undertake'). The enemy army destroys itself: the internecine confusion where allies become adversaries is the Gideon-pattern (Judg 7:22) applied on an eschatological scale. 'They seize each other's hand' — possibly in the combat posture, each seizing the opponent. Divine judgment operates through the enemy's self-destruction.</p>",
    "14": "<p><span class='term'>Judah also will fight in Jerusalem. The wealth of all the surrounding nations will be gathered — gold, silver, and clothing in great abundance</span> — <em>vegam Yehudah tilachem biYerushalaim</em>: Judah participates in the eschatological battle — the reversal of v2 where Judah was passive. <em>Vecheyl kol-ha-goyim saviv ye'asof</em> (the wealth of all surrounding nations will be gathered) — the eschatological reversal: the nations who came to plunder Jerusalem end up contributing their wealth to it. The three-term list (gold, silver, clothing in great abundance) echoes the spoil formulas of the exodus from Egypt (Exod 12:35-36: 'the Israelites stripped the Egyptians') — the final Exodus reversal on a global scale.</p>",
    "15": "<p><span class='term'>The same plague will strike the horses, mules, camels, donkeys, and all the animals in those camps</span> — the five-term animal list extends the plague-judgment beyond humans to the military-logistical infrastructure of the invading armies. The animals are the power-projection system of pre-modern warfare; their destruction ensures the complete neutralization of the enemy forces. The same pattern operates in the Exodus plagues (Exod 9:3-6: plague on livestock) — eschatological judgment recapitulates Exodus judgment in intensified form.</p>",
    "16": "<p><span class='term'>Then all who survive from the nations that came against Jerusalem will go up year after year to worship the King, the LORD of Hosts, and to celebrate the Feast of Tabernacles</span> — <em>vehayah kol ha-notar mikol ha-goyim... vealu mishana b'shanah lehishtachavot laMelekh YHWH tzvaot velachog et-chag ha-sukkot</em>: the survivors of the eschatological war become the eschatological pilgrims. <em>Chag ha-sukkot</em> (Feast of Tabernacles/Booths) — the harvest feast celebrating the wilderness-dwelling period was the most universally attended of the three pilgrimage feasts; it was also the feast most associated with rainfall prayer and eschatological hope (v17). The NT Sukkot connection: John 7:37-38 records Jesus's great invitation on 'the last day of the feast' (Sukkot), and Revelation 7:15 ('he who sits on the throne will shelter them with his presence') uses <em>tabernacle/dwell</em> language for the eschatological condition.</p>",
    "17": "<p><span class='term'>If any of the families of the earth do not go up to Jerusalem to worship the King, the LORD of Hosts, no rain will fall on them</span> — the conditional covenant structure is maintained even in the eschatological period: non-worship incurs the drought-curse. <em>Geshem</em> (rain) was the primary symbol of divine blessing in the agricultural ANE (Deut 28:12: 'the LORD will open to you his good treasury, the heavens, to give the rain to your land in its season'). The withholding of rain as the eschatological punishment for non-pilgrimage applies the Sinaitic covenant-curse (Deut 28:23-24) to the nations in the eschatological age — the universal covenant that encompasses all people.</p>",
    "18": "<p><span class='term'>If the family of Egypt does not go up and come, no rain will fall on them</span> — Egypt is named specifically because it does not depend on rain but on the Nile. The text adjusts the curse accordingly: not rain-withholding but a different plague (<em>ha-maggefah</em>) — possibly the plague of v12. Egypt's exemption from rain-dependence cannot exempt it from covenant-accountability; YHWH adjusts the punishment to the specific circumstances. This is the covenant's precision rather than its rigidity: the principle (accountability for non-worship) remains constant; the mechanism is calibrated to the recipient.</p>",
    "19": "<p><span class='term'>This will be the punishment for Egypt and for every nation that does not come up to celebrate the Feast of Tabernacles</span> — the principle is universalized beyond Egypt to every non-participant nation. The eschatological covenant is genuinely universal: there is no people or nation exempt from the obligation to worship the King of all the earth (v9). The <em>Khatta'at</em> (sin, punishment) language places the failure to worship in the category of formal covenant violation — not mere negligence but transgression with judicial consequence. The covenant that was particular (Israel) has become universal without becoming less covenantal.</p>",
    "20": "<p><span class='term'>'Holy to the LORD' will be inscribed on the bells of the horses, and the cooking pots in the LORD's house will be as sacred as the sacrificial bowls before the altar</span> — <em>qodesh l-YHWH</em>: this inscription was on the golden headband of the High Priest (Exod 28:36-37: 'you shall make a plate of pure gold and engrave on it, as on a seal, Holy to the LORD'), worn on his forehead as the sign of the highest sanctity. In the eschatological day, this phrase is inscribed on <em>horse bells</em> — the most profane elements of military culture. The sacred-secular boundary is abolished; the cooking pots (<em>siroth</em>) of the temple are placed on the same level as the <em>mizraqot</em> (sacrificial bowls) before the altar. The eschatological vision of pervasive holiness: all of life is priestly service.</p>",
    "21": "<p><span class='term'>On that day every pot in Jerusalem and Judah will be holy to the LORD of Hosts. All who sacrifice will be able to take one and boil their meat in it. And there will no longer be a merchant in the house of the LORD of Hosts on that day</span> — <em>vehayah kol sir biYerushalaim uvIhudah qodesh l-YHWH tzvaot</em>: the holiness is no longer restricted to temple utensils but extends to every pot in every kitchen in Jerusalem and Judah. The abolition of the sacred-secular distinction is complete. <em>Ve-lo yihyeh Kena'ani od beveyt YHWH tzvaot bayom hahu</em>: <em>Kena'ani</em> means both 'Canaanite' (ethnic) and 'merchant/trader' (functional — the Phoenician Canaanites were the traders of the ancient world). No commercial exploitation in YHWH's house on that day. Jesus's temple cleansing (John 2:16: 'do not make my Father's house a house of trade') is the messianic anticipation of this verse in advance: he enacts Zechariah 14:21 in his own person, declaring that the trading in the temple must end — pointing forward to the eschatological house where it will be permanently abolished.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'zechariah')
    merge_comm(existing, ZECHARIAH)
    save_comm('mkt-original', 'zechariah', existing)

if __name__ == '__main__':
    main()
